function getDestinationById(id) {
  return DESTINATIONS.find(d => d.id === id);
}

function filterDestinations({ type, state, maxPrice, month, search } = {}) {
  return DESTINATIONS.filter(d => {
    if (type && d.type !== type) return false;
    if (state && d.state !== state) return false;
    if (maxPrice && d.minPrice > maxPrice) return false;
    if (month && !d.bestMonthsList.includes(month)) return false;
    if (search) {
      const q = search.toLowerCase();
      if (!d.name.toLowerCase().includes(q) &&
          !d.state.toLowerCase().includes(q) &&
          !d.shortDesc.toLowerCase().includes(q) &&
          !d.type.toLowerCase().includes(q) &&
          !d.region.toLowerCase().includes(q)) return false;
    }
    return true;
  });
}

function getPriceTierLabel(tier) {
  return PRICE_TIERS[tier]?.label || tier;
}

function getPriceTierColor(tier) {
  const colors = {
    cheapest: 'bg-emerald-100 text-emerald-800',
    budget: 'bg-blue-100 text-blue-800',
    good: 'bg-indigo-100 text-indigo-800',
    better: 'bg-violet-100 text-violet-800',
    best: 'bg-orange-100 text-orange-800',
    luxury: 'bg-rose-100 text-rose-800',
    extra_luxury: 'bg-amber-100 text-amber-800',
  };
  return colors[tier] || 'bg-gray-100 text-gray-800';
}

